// ── Shared secret authentication ──────────────────────────────
// Check that the request includes the correct X-Upload-Secret header.
// This matches the secret sent by the HTML form and rejects anything else.
const providedSecret = $input.first().json.headers?.['x-upload-secret'] || 
                       $input.first().json.headers?.['X-Upload-Secret'] || '';
const expectedSecret = $env.UPLOAD_SECRET || '';

if (expectedSecret && providedSecret !== expectedSecret) {
  // Return an error item that the Upload Valid? IF node will catch
  return [{ json: { error: true, message: 'Unauthorized: invalid or missing upload secret.' } }];
}

const body = $input.first().json.body || $input.first().json;
const binaryData = $input.first().binary || {};

const category = body.category || '';
const description = body.description || '';
const uploaderName = body.uploader_name || 'Unknown';
const validCategories = ['services', 'billing', 'faq', 'compliance', 'vendor', 'other'];

if (!validCategories.includes(category)) {
  throw new Error('INVALID_CATEGORY: ' + category);
}

const fileKey = Object.keys(binaryData)[0];
if (!fileKey) throw new Error('NO_FILE: No file found in upload');

const fileName = binaryData[fileKey].fileName || 'upload';
const mimeType = binaryData[fileKey].mimeType || '';
const allowedMimes = ['application/pdf', 'application/vnd.openxmlformats-officedocument.wordprocessingml.document'];
if (!allowedMimes.includes(mimeType)) throw new Error('INVALID_FILE_TYPE: ' + mimeType);

return [{ json: { category, description, uploader_name: uploaderName, file_key: fileKey, file_name: fileName, mime_type: mimeType, timestamp: new Date().toISOString() }, binary: binaryData }];

